export const BP_CATEGORY_META: Record<
  BpCategory,
  { label: string; chip: string }
> = {
  normal: {
    label: "Normal for age",
    chip: "bg-emerald-100 text-emerald-700 dark:bg-emerald-950 dark:text-emerald-300",
  },
  elevated: {
    label: "Elevated",
    chip: "bg-amber-100 text-amber-700 dark:bg-amber-950 dark:text-amber-300",
  },
  stage1: {
    label: "Stage 1 hypertension",
    chip: "bg-rose-100 text-rose-700 dark:bg-rose-950 dark:text-rose-300",
  },
  stage2: {
    label: "Stage 2 hypertension",
    chip: "bg-rose-100 text-rose-700 dark:bg-rose-950 dark:text-rose-300",
  },
};

// "50th"/"92nd"/"95th" — ordinal suffix for the percentile copy.
export function ordinal(n: number): string {
  const abs = Math.abs(Math.round(n));
  const mod100 = abs % 100;
  if (mod100 >= 11 && mod100 <= 13) return `${abs}th`;
  switch (abs % 10) {
    case 1:
      return `${abs}st`;
    case 2:
      return `${abs}nd`;
    case 3:
      return `${abs}rd`;
    default:
      return `${abs}th`;
  }
}

// Human phrase for a BP percentile: "92nd percentile", "≥ 95th percentile"
// (clamped high), "≤ 50th percentile" (clamped low).
export function formatBpPercentile(ctx: PediatricBpContext): string {
  if (ctx.clamped === "high") return `≥ ${ordinal(ctx.percentile)} percentile`;
  if (ctx.clamped === "low") return `≤ ${ordinal(ctx.percentile)} percentile`;
  return `${ordinal(ctx.percentile)} percentile`;
}
